script:
export const meta = {
  name: 'pass8-verify',
  description: 'Pass-8: two independent agents blind-verify each survivor is a true positive',
  phases: [{ title: 'Verify' }],
}

const REPO = '/Users/[REDACTED]/hc-assay'

const SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['verdict', 'reasoning'],
  properties: {
    verdict: { type: 'string', enum: ['TRUE_POSITIVE', 'FALSE_POSITIVE'] },
    reasoning: { type: 'string' },
  },
}

const FINDINGS = [
  { key: 'K-REL-1', sev: 'high', title: 'SIGTERM handler swallows process termination when prior disposition is SIG_DFL',
    loc: 'src/assay_engine/observability/tracing.py ~148-156 (_install_flush_on_exit._handler)',
    claim: 'The installed SIGTERM handler flushes/shuts down the tracer then does `if callable(prior): prior(signum, frame)`. When no prior Python handler exists, prior == signal.SIG_DFL which is NOT callable, so the handler returns WITHOUT terminating — it replaced the default terminate disposition, so the process no longer dies on SIGTERM (docker stop / kill / k8s) until SIGKILL escalation. Tracing is on by default; bootstrap runs on the main thread in run/resume paths. The unit test only asserts flush/shutdown ran, never that termination still happens.' },
  { key: 'K-OPS-1', sev: 'high', title: 'Lockfile-sync guard re-resolves against live PyPI (no --exclude-newer); spuriously fails',
    loc: '.github/workflows/ci.yml ~126-146 (audit job "Lockfiles are in sync") + scripts/regenerate_lockfiles.sh',
    claim: 'The gate runs `uv pip compile pyproject.toml --all-extras --universal --generate-hashes` and diffs vs the committed requirements.lock. With pyproject ranges and unconstrained transitive deps and NO --exclude-newer/resolution-date pin, uv resolves the NEWEST in-range versions at CI wall-clock time, so the gate goes red the instant any of ~218 transitive packages publishes an in-range release — independent of whether the PR touches deps. Claimed to be CURRENTLY failing on a clean checkout (e.g. mlflow 3.13.0→3.14.0). The reproducibility guard is itself irreproducible. VERIFY whether this actually re-resolves to newer (reproduce with the CI-pinned uv==0.11.21) and whether it blocks merges.' },
  { key: 'K-OBS-2', sev: 'high', title: 'Provenance artifact silently dropped + temp file leaked on hashable-but-non-JSON payload value',
    loc: 'src/assay_engine/pipeline.py ~733-756 (_log_trail) + entries_to_records / _frozen.freeze',
    claim: 'freeze() only rejects UNHASHABLE values, so a hashable-but-non-JSON leaf (bytes/datetime/Enum) in a payload (e.g. gate evidence) is stored and survives unfreeze(). In _log_trail, json.dump(entries_to_records(...)) raises TypeError BEFORE `path = fh.name`, so (a) the NamedTemporaryFile(delete=False) is orphaned on disk with provenance contents (the try/finally cleanup is unreachable because path is unassigned), and (b) track() catches the TypeError and records only a generic tracking_error entry — the provenance artifact never attaches to the MLflow run, with NO warning logged. Breaks the #H-013 (no temp-file leak) and #G-009 (provenance attaches) guarantees silently. VERIFY by constructing such a payload.' },
  { key: 'K-SEC-1', sev: 'medium', title: 'Local-URI guard rejects Unix-domain-socket Postgres host',
    loc: 'src/assay_engine/_local.py ~126-153 (require_local_uri) + is_loopback_host',
    claim: 'require_local_uri() raises NonLocalEndpointError for a libpq Unix-domain-socket host (leading "/", e.g. host=/var/run/postgresql, or postgresql:///db?host=/var/run/postgresql), because is_loopback_host("/var/run/postgresql") is False. A leading-"/" host is libpq standard for a local Unix socket — strictly more data-sovereign than TCP loopback (which IS accepted), so the guard refuses the one local form that never touches the network. Reachable: checkpoint.py routes operator ASSAY_POSTGRES_URL through require_local_uri. No test/doc declares the rejection intentional. VERIFY empirically and confirm UNC //server/share still fails closed.' },
  { key: 'K-OPS-2', sev: 'medium', title: 'regenerate_lockfiles.sh omits requirements-build.lock which CI gates',
    loc: 'scripts/regenerate_lockfiles.sh (+ .github/workflows/ci.yml build-lock sync step + dependabot.yml note)',
    claim: 'CI fails with "requirements-build.lock is stale" by diffing it against a fresh `uv pip compile <(printf "hatchling\\neditables\\n") ...`. The single documented remediation (scripts/regenerate_lockfiles.sh, referenced by dependabot.yml and CI error text) does NOT regenerate requirements-build.lock — grep -c returns 0. A maintainer following the documented workflow regenerates the other two locks and stays red, with no scripted path to fix the build lock (must hand-reconstruct the CI command). build-lock pins trove-classifiers (frequent releases).' },
  { key: 'K-OPS-3', sev: 'medium', title: 'Coverage measured but never enforced (vacuous gate)',
    loc: '.github/workflows/ci.yml ~105-106 (integration job) + pyproject.toml (no [tool.coverage], no fail-under)',
    claim: 'The integration job runs `pytest -q --cov=assay_engine --cov-report=term-missing` with NO --cov-fail-under, no [tool.coverage.report] fail_under, no .coveragerc. pytest --cov without a threshold exits 0 regardless of coverage, so a refactor deleting tests or adding a large untested module still passes CI green. pyproject comments frame pytest-cov as added "to gate coverage (#103)" yet nothing enforces it.' },
]

function prompt(f, lens) {
  return `You are an independent blind verifier (verifier ${lens}) for a production-hardening pass on the hc-assay repo at ${REPO}. Determine whether this finding is a TRUE_POSITIVE (a genuine production-readiness defect that should be fixed) or a FALSE_POSITIVE (false, already-mitigated, out-of-scope by design, or not a real defect). Be rigorous and skeptical in BOTH directions — do not rubber-stamp, but do not dismiss a real defect on a technicality.

Out-of-scope-by-design exclusions (these are NOT defects): the dataset-agnostic engine receiving opaque inputs; optional import-guarded backends; transcripts intentionally committed (and scrubbed); on-box/loopback data-sovereignty; documented honest-scope limitations.

FINDING ${f.key} (${f.sev}): ${f.title}
Location: ${f.loc}
Claim: ${f.claim}

Read the actual code (Read/Grep/Bash) and, where the claim is empirically testable, REPRODUCE it (cd ${REPO} && source .venv/bin/activate && python ... ; use "python -m pytest" not bare pytest). Judge ONLY ${f.key}. Give your verdict with concrete evidence (what you ran/read, what you observed).`
}

phase('Verify')
const results = await parallel(
  FINDINGS.flatMap((f) => [
    () => agent(prompt(f, 'A'), { label: `verify:${f.key}:A`, phase: 'Verify', schema: SCHEMA }).then((v) => ({ key: f.key, sev: f.sev, lens: 'A', v })),
    () => agent(prompt(f, 'B'), { label: `verify:${f.key}:B`, phase: 'Verify', schema: SCHEMA }).then((v) => ({ key: f.key, sev: f.sev, lens: 'B', v })),
  ])
)

const clean = results.filter(Boolean)
const byKey = {}
for (const r of clean) {
  byKey[r.key] = byKey[r.key] || { sev: r.sev, votes: [] }
  byKey[r.key].votes.push({ lens: r.lens, ...r.v })
}
const summary = Object.entries(byKey).map(([key, o]) => {
  const bothTP = o.votes.length === 2 && o.votes.every((x) => x.verdict === 'TRUE_POSITIVE')
  return { key, sev: o.sev, bothTP, votes: o.votes }
})
log('PASS-8 VERIFICATION:')
for (const s of summary) log(`${s.key} (${s.sev}): ${s.bothTP ? 'BOTH TRUE_POSITIVE → fix' : 'SPLIT/REJECTED'} — ${s.votes.map((v) => v.lens + ':' + v.verdict).join(', ')}`)
return { summary }
